namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => s.ToDto())
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment?.ToDto();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = Shipment.FromDto(dto);
        shipment.TrackingNumber = GenerateTrackingNumber();
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment.ToDto();
    }

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException($"Shipment {id} not found.");

        shipment.Status = status;
        if (status == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return shipment.ToDto();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}
