@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260520-100001)"
                   @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning">@errorMessage</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>Tracking Number:</strong> @shipment.TrackingNumber
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>

                        <dt>Carrier</dt>
                        <dd>@shipment.CarrierName</dd>

                        <dt>Weight</dt>
                        <dd>@shipment.WeightKg.ToString("F1") kg</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>

                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd>@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>

            <h5 class="mt-3">Shipment Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
            if (shipment is null)
                errorMessage = "No shipment found with that tracking number.";
        }
        catch
        {
            errorMessage = "An error occurred while looking up the shipment. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-warning text-dark",
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-primary",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-warning",
        _ => "bg-success"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="input-group" style="max-width: 400px;">
        <input type="text" class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
        @if (!string.IsNullOrEmpty(filterText))
        {
            <button class="btn btn-outline-secondary" @onclick="() => filterText = string.Empty">✕</button>
        }
    </div>
    <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient</label>
                    <input type="text" class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Carrier</label>
                    <input type="text" class="form-control" @bind="newShipment.CarrierName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Weight (kg)</label>
                    <input type="number" class="form-control" @bind="newShipment.WeightKg" step="0.1" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
            </div>
            <div class="mt-3">
                <button class="btn btn-primary me-2" @onclick="CreateShipment" disabled="@isSaving">
                    @if (isSaving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Create
                </button>
                <button class="btn btn-outline-secondary" @onclick="() => showCreateForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (isLoading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is null)
{
    <div class="alert alert-danger">Failed to load shipments.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.ShippedDate.ToString("MMM dd")</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Returned)
                            {
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        @onchange="e => UpdateStatus(s.Id, e)">
                                    <option value="" selected disabled>Update…</option>
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        @if (status != s.Status)
                                        {
                                            <option value="@((int)status)">@status</option>
                                        }
                                    }
                                </select>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

