+                    <label class="form-label">Estimated Delivery</label>
+                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
+                </div>
+            </div>
+            <div class="mt-3">
+                <button class="btn btn-primary me-2" @onclick="CreateShipment" disabled="@isSaving">
+                    @if (isSaving)
+                    {
+                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
+                    }
+                    Create
+                </button>
+                <button class="btn btn-outline-secondary" @onclick="() => showCreateForm = false">Cancel</button>
+            </div>
+        </div>
+    </div>
+}
+
+@if (isLoading)
+{
+    <p><em>Loading shipments...</em></p>
+}
+else if (shipments is null)
+{
+    <div class="alert alert-danger">Failed to load shipments.</div>
+}
+else
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover">
+            <thead class="table-dark">
+                <tr>
+                    <th>Tracking #</th>
+                    <th>Destination</th>
+                    <th>Recipient</th>
+                    <th>Status</th>
+                    <th>Shipped</th>
+                    <th>Est. Delivery</th>
+                    <th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var s in FilteredShipments)
+                {
+                    <tr>
+                        <td><code>@s.TrackingNumber</code></td>
+                        <td>@s.Destination</td>
+                        <td>@s.RecipientName</td>
+                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
+                        <td>@s.ShippedDate.ToString("MMM dd")</td>
+                        <td>@s.EstimatedDelivery.ToString("MMM dd")</td>
+                        <td>
+                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Returned)
+                            {
+                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
+                                        @onchange="e => UpdateStatus(s.Id, e)">
+                                    <option value="" selected disabled>Update…</option>
+                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                                    {
+                                        @if (status != s.Status)
+                                        {
+                                            <option value="@((int)status)">@status</option>
+                                        }
+                                    }
+                                </select>
+                            }
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
+}
+
+@code {
+    private List<ShipmentDto>? shipments;
+    private bool isLoading = true;
+    private string filterText = string.Empty;
+
+    private bool showCreateForm;
+    private ShipmentDto newShipment = new();
+    private bool isSaving;
+
+    private IEnumerable<ShipmentDto> FilteredShipments =>
+        shipments?.Where(s =>
+            string.IsNullOrEmpty(filterText) ||
+            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
+            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
+            s.RecipientName.Contains(filterText, StringComparison.OrdinalIgnoreCase))
+        ?? [];
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        isLoading = true;
+        try
+        {
+            shipments = await ShipmentService.GetAllShipmentsAsync();
+        }
+        catch
+        {
+            shipments = null;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void ShowCreateForm()
+    {
+        newShipment = new ShipmentDto
+        {
+            ShippedDate = DateTime.UtcNow,
+            EstimatedDelivery = DateTime.UtcNow.AddDays(7)
+        };
+        showCreateForm = true;
+    }
+
+    private async Task CreateShipment()
+    {
+        isSaving = true;
+        try
+        {
+            await ShipmentService.CreateShipmentAsync(newShipment);
+            showCreateForm = false;
+            await LoadShipments();
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+
+    private async Task UpdateStatus(int id, ChangeEventArgs e)
+    {
+        if (e.Value is string val && int.TryParse(val, out var statusInt))
+        {
+            var status = (ShipmentStatus)statusInt;
+            await ShipmentService.UpdateShipmentStatusAsync(id, status);
+            await LoadShipments();
+        }
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-info text-dark",
+        ShipmentStatus.Delayed => "bg-danger",
+        ShipmentStatus.Returned => "bg-warning text-dark",
+        ShipmentStatus.Pending => "bg-secondary",
+        ShipmentStatus.PickedUp => "bg-primary",
+        _ => "bg-secondary"
+    };
+}
+

